import { corsHeaders } from "../_shared/cors.ts";
import { requireZernioAuth } from "../_shared/zernioAuth.ts";
import { zernioFetch } from "../_shared/zernioClient.ts";

const ALLOWED_TYPES = new Set([
  "image/jpeg",
  "image/jpg",
  "image/png",
  "image/webp",
  "image/gif",
  "video/mp4",
]);

function jsonResponse(status: number, body: unknown) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

type PresignBody = {
  filename?: string;
  content_type?: string;
};

export default async function handler(req: Request): Promise<Response> {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  if (req.method !== "POST") return jsonResponse(405, { ok: false, error: "Method not allowed" });

  const auth = await requireZernioAuth(req);
  if (auth instanceof Response) return auth;

  let body: PresignBody;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { ok: false, error: "JSON inválido" });
  }

  const filename = (body.filename ?? "upload.jpg").trim();
  const contentType = (body.content_type ?? "image/jpeg").trim().toLowerCase();
  if (!ALLOWED_TYPES.has(contentType)) {
    return jsonResponse(400, { ok: false, error: "Tipo de archivo no permitido" });
  }

  try {
    const presign = await zernioFetch<{
      uploadUrl?: string;
      publicUrl?: string;
      key?: string;
      type?: string;
    }>("/media/presign", {
      method: "POST",
      body: { filename, contentType },
    });

    if (!presign.uploadUrl || !presign.publicUrl) {
      return jsonResponse(502, { ok: false, error: "Respuesta presign incompleta" });
    }

    return jsonResponse(200, { ok: true, ...presign });
  } catch (e) {
    return jsonResponse(500, { ok: false, error: (e as Error).message });
  }
}

// CORS helper para Edge Functions.
//
// En producción, setear el secret `ALLOWED_ORIGINS` en Supabase con la lista
// de orígenes separados por coma (ej: "https://app.skalemotors.cl,https://skalemotors.cl").
// Si no está seteado, mantiene el comportamiento legacy (wildcard).
//
// Uso recomendado en handlers:
//   const cors = getCorsHeaders(req);
//   ...new Response(..., { headers: { ...cors } });
//
// Compatibilidad: corsHeaders (constante con `*`) se mantiene para no romper
// las funciones existentes hasta que se migren una a una.

const ALLOWED_HEADERS =
  "authorization, x-client-info, apikey, content-type, x-api-key, x-webhook-token, x-signature, x-hub-signature-256, idempotency-key";
const ALLOWED_METHODS = "GET,POST,OPTIONS";
const MAX_AGE = "86400";

function getAllowedOrigins(): string[] | null {
  const raw = Deno.env.get("ALLOWED_ORIGINS");
  if (!raw) return null;
  return raw.split(",").map((s) => s.trim()).filter(Boolean);
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("origin");
  const allowed = getAllowedOrigins();
  let allowOrigin = "*";
  if (allowed && allowed.length > 0) {
    allowOrigin = origin && allowed.includes(origin) ? origin : allowed[0];
  }
  return {
    "Access-Control-Allow-Origin": allowOrigin,
    "Vary": "Origin",
    "Access-Control-Allow-Headers": ALLOWED_HEADERS,
    "Access-Control-Allow-Methods": ALLOWED_METHODS,
    "Access-Control-Max-Age": MAX_AGE,
  };
}

// Constante compartida. Si `ALLOWED_ORIGINS` está seteado en Supabase Secrets,
// usa el primer origen permitido (lockdown CORS). Si no, fallback a `*` (legacy).
// Para validación per-request real (multi-origen con echo del origen del request),
// usar getCorsHeaders(req).
function resolveDefaultAllowOrigin(): string {
  const allowed = getAllowedOrigins();
  if (allowed && allowed.length > 0) return allowed[0];
  return "*";
}

export const corsHeaders = {
  "Access-Control-Allow-Origin": resolveDefaultAllowOrigin(),
  "Vary": "Origin",
  "Access-Control-Allow-Headers": ALLOWED_HEADERS,
  "Access-Control-Allow-Methods": ALLOWED_METHODS,
  "Access-Control-Max-Age": MAX_AGE,
};

import { createClient, type SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";

export type ZernioAuthContext = {
  userId: string;
  tenantId: string;
  role: string;
  branchId: string | null;
  userClient: SupabaseClient;
  admin: SupabaseClient;
};

function getEnv(name: string): string | null {
  return Deno.env.get(name) ?? null;
}

export async function requireZernioAuth(req: Request): Promise<ZernioAuthContext | Response> {
  const authHeader = req.headers.get("authorization") || "";
  if (!authHeader.toLowerCase().startsWith("bearer ")) {
    return new Response(JSON.stringify({ ok: false, error: "Missing auth" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const supabaseUrl = getEnv("SUPABASE_URL") ?? getEnv("PROJECT_URL");
  const anonKey = getEnv("SUPABASE_ANON_KEY");
  const serviceRoleKey = getEnv("SUPABASE_SERVICE_ROLE_KEY") ?? getEnv("SERVICE_ROLE_KEY");
  if (!supabaseUrl || !anonKey || !serviceRoleKey) {
    return new Response(JSON.stringify({ ok: false, error: "Missing Supabase env vars" }), {
      status: 500,
      headers: { "Content-Type": "application/json" },
    });
  }

  const userClient = createClient(supabaseUrl, anonKey, {
    global: { headers: { Authorization: authHeader } },
  });
  const { data: userData, error: userErr } = await userClient.auth.getUser();
  if (userErr || !userData?.user) {
    return new Response(JSON.stringify({ ok: false, error: "Invalid auth" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const admin = createClient(supabaseUrl, serviceRoleKey, { auth: { persistSession: false } });
  const { data: profile, error: profileErr } = await admin
    .from("users")
    .select("id, tenant_id, branch_id, role")
    .eq("id", userData.user.id)
    .maybeSingle();

  if (profileErr || !profile?.tenant_id) {
    return new Response(JSON.stringify({ ok: false, error: "Perfil de usuario no encontrado" }), {
      status: 403,
      headers: { "Content-Type": "application/json" },
    });
  }

  return {
    userId: userData.user.id,
    tenantId: profile.tenant_id,
    role: profile.role ?? "vendedor",
    branchId: profile.branch_id ?? null,
    userClient,
    admin,
  };
}

const ZERNIO_API_BASE = "https://zernio.com/api/v1";

export async function zernioFetch<T>(
  path: string,
  init?: { method?: string; body?: unknown },
): Promise<T> {
  const apiKey = Deno.env.get("ZERNIO_API_KEY");
  if (!apiKey) {
    throw new Error("ZERNIO_API_KEY no configurada en Supabase Secrets");
  }

  const res = await fetch(`${ZERNIO_API_BASE}${path}`, {
    method: init?.method ?? "GET",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: init?.body !== undefined ? JSON.stringify(init.body) : undefined,
  });

  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg =
      (json as { message?: string }).message ??
      (json as { error?: string }).error ??
      res.statusText;
    throw new Error(typeof msg === "string" ? msg : "Error en Zernio API");
  }
  return json as T;
}
